// Normalize incoming data from Vapi and generate final calendar event data.
// Handles timezone reliably using luxon.
const { DateTime } = require('luxon');
const body = $json.body || $json || {};
const rawTitle = body.title || body.appointment_title || body.summary || 'Appointment';
const rawDescription = body.description || 'Booked automatically by VANV AI Receptionist.';
const rawLocation = body.location || 'Online';
const rawStart = body.start_time;
const rawEnd = body.end_time;
if (!rawStart) throw new Error('Missing start_time in request body.');
function parseToLuxon(ts){ if(!ts)return null; let dt=DateTime.fromISO(ts,{setZone:true}); if(!dt.isValid){dt=DateTime.fromISO(ts,{zone:'America/Detroit'});} if(!dt.isValid){throw new Error('Invalid datetime provided: '+ts);} return dt;}
const startLuxon=parseToLuxon(rawStart);
let endLuxon=rawEnd?parseToLuxon(rawEnd):startLuxon.plus({hours:1});
const startUtcIso=startLuxon.toUTC().toISO();
const endUtcIso=endLuxon.toUTC().toISO();
const startPretty=startLuxon.toFormat('yyyy-LL-dd HH:mm ZZZZ');
const endPretty=endLuxon.toFormat('yyyy-LL-dd HH:mm ZZZZ');
const tzName=startLuxon.zoneName;
return [{json:{title:rawTitle,description:rawDescription,location:rawLocation,start_time_iso:startUtcIso,end_time_iso:endUtcIso,start_time_local:startPretty,end_time_local:endPretty,timezone:tzName}}];

// Build a clean response to send back to Vapi
const bookingData = $items('Prepare Booking Data',0).json;
const calendarResult = $json;
return [{json:{success:true,message:`Appointment booked: ${bookingData.title} on ${bookingData.start_time_local} (${bookingData.timezone})`,calendar_event_id:calendarResult.id||null,calendar_link:calendarResult.htmlLink||null,start_time_local:bookingData.start_time_local,end_time_local:bookingData.end_time_local,timezone:bookingData.timezone}}];
